svg.script:
//
(function() {
  var svg    = document.getElementById('root');
  var ns     = 'http://www.w3.org/2000/svg';

  document.getElementById('dark-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
    if (svg.classList.toggle('dark')) { thumb.setAttribute('cx','52'); lbl.textContent='Light'; swapFills(true); }
    else                              { thumb.setAttribute('cx','16'); lbl.textContent='Dark';  swapFills(false); }
  });
  function swapFills(dark) {
    svg.querySelectorAll('path[fill]').forEach(function(p) {
      var f = p.getAttribute('fill') || '';
      var m = f.match(/url\(#(a[1-5])(d?)\)/);
      if (!m) return;
      p.setAttribute('fill', dark ? 'url(#' + m[1] + 'd)' : 'url(#' + m[1] + ')');
    });
  }
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
  var xs = [68, 180, 291, 403, 515, 627, 738, 850];
  var series = [
    { label:'Cyan',    color:'#00F2FF', stroke:'#003D50', grad:'c1', vals:[32,38,41,48,52,61,68,72], ys:[372,348,336,308,292,256,228,212] },
    { label:'Emerald', color:'#10B981', stroke:'#033D2A', grad:'c2', vals:[28,31,35,40,44,49,55,62], ys:[388,376,360,340,324,304,280,252] },
    { label:'Amber',   color:'#F59E0B', stroke:'#4A2200', grad:'c3', vals:[18,22,25,29,25,28,31,35], ys:[428,412,400,384,400,388,376,360] },
    { label:'Rose',    color:'#F43F5E', stroke:'#881337', grad:'c4', vals:[12,15,18,14,17,20,16,22], ys:[452,440,428,444,432,420,436,412] },
    { label:'Other',   color:'#64748B', stroke:'#1E293B', grad:'c5', vals:[10,13,11,15,13,17,15,19], ys:[460,448,456,440,448,432,440,424] },
  ];

  var dotsLayer = document.getElementById('dots-layer');
  var tipLayer  = document.getElementById('tip-layer');
  var allTips   = {};

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  series.forEach(function(s, si) {
    xs.forEach(function(x, qi) {
      var y = s.ys[qi], val = s.vals[qi];
      var key = si+'_'+qi;
      var delay = (si*0.15 + qi*0.06)+'s';

      var dg = el('g', { 'class':'dot-g', id:'d'+key });
      dotsLayer.appendChild(dg);

      var outer = el('circle', { cx:x, cy:y, r:10, fill:s.color, opacity:0.18, 'class':'dot-outer' });
      dg.appendChild(outer);

      var inner = el('g', { 'class':'dot-inner', style:'transform-origin:'+x+'px '+y+'px; animation-delay:'+delay });
      inner.appendChild(el('circle', { cx:x, cy:y, r:6, fill:'url(#'+s.grad+')', 'class':'dot-core', style:'--dot-glow:url(#glow-'+s.grad+')' }));
      inner.appendChild(el('circle', { cx:x, cy:y, r:6, fill:'url(#dotshine)', 'class':'dot-shine' }));
      inner.appendChild(el('circle', { cx:x, cy:y, r:6, fill:'none', stroke:s.color, 'stroke-width':'1', 'stroke-opacity':'0.5' }));
      dg.appendChild(inner);

      var bw = Math.max(80, s.label.length*7+40), bh = 48, hw = bw/2, hh = bh/2, TAIL = 14;
      var bCx = x;
      if (bCx-hw < 68)  bCx = 68+hw;
      if (bCx+hw > 850) bCx = 850-hw;
      var bCy = y - hh - TAIL - 6;

      var tipG = el('g', { 'class':'tip', id:'t'+key });
      tipLayer.appendChild(tipG);
      allTips[key] = tipG;

      var tailBaseY = bCy+hh;
      tipG.appendChild(el('rect', { x:bCx-hw, y:bCy-hh, width:bw, height:bh, rx:8, 'class':'bub-bg', filter:'url(#tipshadow)' }));
      tipG.appendChild(el('rect', { x:bCx-hw, y:bCy-hh, width:bw, height:bh, rx:8, 'class':'bub-bdr' }));
      tipG.appendChild(el('polygon', { points:(bCx+10)+','+(tailBaseY-1)+' '+(bCx-10)+','+(tailBaseY-1)+' '+x+','+(tailBaseY+TAIL+3), 'class':'bub-tip-p' }));
      tipG.appendChild(el('path', { d:'M'+(bCx+10)+','+(tailBaseY-1)+' '+x+','+(tailBaseY+TAIL+3)+' '+(bCx-10)+','+(tailBaseY-1), 'class':'bub-bdr', fill:'none', 'stroke-width':'1' }));

      var tv = el('text', { x:bCx, y:bCy-7, 'text-anchor':'middle', 'dominant-baseline':'central', 'class':'bub-val' });
      tv.textContent = '$'+val+'M';
      tipG.appendChild(tv);
      var tl = el('text', { x:bCx, y:bCy+8, 'text-anchor':'middle', 'dominant-baseline':'central', 'class':'bub-lbl' });
      tl.textContent = s.label + ' · ' + quarters[qi];
      tipG.appendChild(tl);

      var ch = document.getElementById('ch'+qi);
      dg.addEventListener('mouseenter', function() { allTips[key].style.opacity='1'; if(ch) ch.style.opacity='1'; outer.setAttribute('r','13'); outer.setAttribute('opacity','0.28'); });
      dg.addEventListener('mouseleave', function() { allTips[key].style.opacity='';  if(ch) ch.style.opacity=''; outer.setAttribute('r','10'); outer.setAttribute('opacity','0.18'); });
    });
  });

  /* ── URL param: ?theme=dark|light sets initial mode ── */
  (function() {
    var params = new URLSearchParams(window.location.search);
    if (params.get('theme') === 'dark') {
      svg.classList.add('dark');
      var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
      if (thumb) thumb.setAttribute('cx','52');
      if (lbl)   lbl.textContent = 'Light';
      swapFills(true);
    }
  })();

})();
//
